create table dirkspzm32.pzm_konten_cfg (
    sid                varchar2(2 char) not null enable,
    firma_nr           number(6, 0) not null enable,
    name               varchar2(100 char) not null enable,
    name_kurz          varchar2(10 char) not null enable,
    typ                varchar2(10 char) not null enable,
    buch_einheit       varchar2(30 char) not null enable,
    info               varchar2(500 char),
    def_max_saldo      number(*, 5),
    def_min_saldo      number(*, 5),
    aktiv              varchar2(1 char) default 'T' not null enable,
    konto_mit_anspruch varchar2(1 char) default 'F' not null enable
);

alter table dirkspzm32.pzm_konten_cfg
    add constraint pzm_konten_cfg
        primary key ( sid,
                      firma_nr,
                      typ,
                      name )
            using index enable;


